INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use a clear service name with scope indicator. Follow the tier-specific pattern. Example: \"Code Review — In-depth security and performance audit\""},"content":{"tips":"Write for a prospective client evaluating your services. Lead with the outcome they get, then explain the process and deliverables. Be specific about what is included."},"formatting":["Bullet lists: deliverables, what is included, prerequisites","Headings: Overview, Deliverables, Process, Timeline, Pricing","Bold: key terms, deliverable names, and availability status","Tables: tier comparisons, feature matrices, pricing breakdowns","Numbered lists: engagement phases or process steps"],"avoid":["Vague service descriptions without concrete deliverables","Missing timeline or availability information","Jargon that clients outside your field would not understand"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":200},"content":{"min":50,"max":15000},"sourceAi":{"min":1,"max":100}}', datetime('now'));
